"""
title: General LLM Tools
author: OWASP LLM Security Project
version: 1.0
description: Common tools for LLM functionality
"""

import os
import requests
import json
import base64
import hashlib
import uuid
from datetime import datetime, timedelta
from pydantic import BaseModel, Field
from typing import Optional, List, Dict, Any

class Tools:
    def __init__(self):
        pass

    def get_user_info(self, __user__: dict = {}) -> str:
        """
        Get the current user's name, email, and ID.
        """
        result = ""
        if "name" in __user__:
            result += f"User: {__user__['name']}"
        if "id" in __user__:
            result += f" (ID: {__user__['id']})"
        if "email" in __user__:
            result += f" (Email: {__user__['email']})"
        if "role" in __user__:
            result += f" (Role: {__user__['role']})"

        return result if result else "User: Unknown"

    def get_current_time(self, timezone: str = Field("UTC", description="Timezone (e.g., UTC, EST, PST)")) -> str:
        """
        Get the current date and time in human-readable format.
        """
        now = datetime.now()
        current_time = now.strftime("%I:%M:%S %p")
        current_date = now.strftime("%A, %B %d, %Y")
        return f"Current Date and Time ({timezone}): {current_date}, {current_time}"

    def calculator(
        self,
        equation: str = Field(..., description="Mathematical equation to calculate")
    ) -> str:
        """
        Calculate mathematical expressions safely.
        """
        try:
            # Basic safety: only allow mathematical operations
            allowed_chars = set('0123456789+-*/().% ')
            if not all(c in allowed_chars for c in equation.replace(' ', '')):
                return "Error: Only basic mathematical operations allowed"

            result = eval(equation)
            return f"{equation} = {result}"
        except Exception as e:
            return f"Error calculating '{equation}': {str(e)}"

    def web_search(
        self,
        query: str = Field(..., description="Search query"),
        num_results: int = Field(5, description="Number of results to return")
    ) -> str:
        """
        Search the web using Google Custom Search API.
        Requires GOOGLE_API_KEY and GOOGLE_CSE_ID environment variables.
        """
        api_key = os.getenv("GOOGLE_API_KEY")
        cse_id = os.getenv("GOOGLE_CSE_ID")

        if not api_key or not cse_id:
            return """Web search not configured. Please set environment variables:

GOOGLE_API_KEY: Get from https://console.developers.google.com/
            1. Create project or select existing
            2. Enable Custom Search API
            3. Create credentials (API Key)

GOOGLE_CSE_ID: Get from https://cse.google.com/
            1. Create custom search engine
            2. Copy the Search Engine ID

Add to your .env file:
GOOGLE_API_KEY=your_api_key_here
GOOGLE_CSE_ID=your_cse_id_here"""

        try:
            url = "https://www.googleapis.com/customsearch/v1"
            params = {
                "key": api_key,
                "cx": cse_id,
                "q": query,
                "num": min(num_results, 10)
            }

            response = requests.get(url, params=params)
            response.raise_for_status()
            data = response.json()

            if "items" not in data:
                return f"No search results found for: {query}"

            results = []
            for item in data["items"]:
                results.append(f"**{item['title']}**\n{item['snippet']}\nURL: {item['link']}\n")

            return f"Search results for '{query}':\n\n" + "\n".join(results)

        except Exception as e:
            return f"Search error: {str(e)}"

    def get_weather(
        self,
        city: str = Field("New York, NY", description="City name for weather information")
    ) -> str:
        """
        Get current weather information using OpenWeatherMap API.
        Requires OPENWEATHER_API_KEY environment variable.
        """
        api_key = os.getenv("OPENWEATHER_API_KEY")
        if not api_key:
            return """Weather API not configured. Get free API key from:
https://openweathermap.org/api

Add to your .env file:
OPENWEATHER_API_KEY=your_api_key_here"""

        try:
            url = "http://api.openweathermap.org/data/2.5/weather"
            params = {
                "q": city,
                "appid": api_key,
                "units": "metric"
            }

            response = requests.get(url, params=params)
            response.raise_for_status()
            data = response.json()

            if data.get("cod") != 200:
                return f"Weather error: {data.get('message')}"

            weather = data["weather"][0]
            main = data["main"]
            wind = data.get("wind", {})

            return f"""Weather in {city}:
🌡️  Temperature: {main['temp']}°C (feels like {main.get('feels_like', 'N/A')}°C)
☁️  Condition: {weather['description'].title()}
💧  Humidity: {main['humidity']}%
🌬️  Wind: {wind.get('speed', 'N/A')} m/s
🔻  Pressure: {main.get('pressure', 'N/A')} hPa"""

        except Exception as e:
            return f"Weather error: {str(e)}"

    def encode_decode(
        self,
        text: str = Field(..., description="Text to encode/decode"),
        operation: str = Field("base64_encode", description="Operation: base64_encode, base64_decode, url_encode, url_decode, hash_md5, hash_sha256")
    ) -> str:
        """
        Encode, decode, or hash text using various methods.
        """
        try:
            if operation == "base64_encode":
                encoded = base64.b64encode(text.encode('utf-8')).decode('utf-8')
                return f"Base64 encoded: {encoded}"
            elif operation == "base64_decode":
                decoded = base64.b64decode(text.encode('utf-8')).decode('utf-8')
                return f"Base64 decoded: {decoded}"
            elif operation == "url_encode":
                from urllib.parse import quote
                encoded = quote(text)
                return f"URL encoded: {encoded}"
            elif operation == "url_decode":
                from urllib.parse import unquote
                decoded = unquote(text)
                return f"URL decoded: {decoded}"
            elif operation == "hash_md5":
                hash_obj = hashlib.md5(text.encode('utf-8'))
                return f"MD5 hash: {hash_obj.hexdigest()}"
            elif operation == "hash_sha256":
                hash_obj = hashlib.sha256(text.encode('utf-8'))
                return f"SHA256 hash: {hash_obj.hexdigest()}"
            else:
                return "Supported operations: base64_encode, base64_decode, url_encode, url_decode, hash_md5, hash_sha256"
        except Exception as e:
            return f"Error in {operation}: {str(e)}"

    def generate_uuid(self, version: int = Field(4, description="UUID version (1 or 4)")) -> str:
        """
        Generate a UUID (Universally Unique Identifier).
        """
        try:
            if version == 1:
                return f"UUID v1: {uuid.uuid1()}"
            elif version == 4:
                return f"UUID v4: {uuid.uuid4()}"
            else:
                return "Supported versions: 1 (timestamp-based) or 4 (random)"
        except Exception as e:
            return f"UUID generation error: {str(e)}"

    def text_analyzer(
        self,
        text: str = Field(..., description="Text to analyze"),
        analysis_type: str = Field("basic", description="Analysis type: basic, detailed, readability")
    ) -> str:
        """
        Analyze text for various metrics.
        """
        try:
            words = text.split()
            sentences = text.split('.') if '.' in text else [text]
            paragraphs = text.split('\n\n') if '\n\n' in text else [text]

            basic_stats = f"""Text Analysis:
📝 Characters: {len(text)}
📄 Words: {len(words)}
📋 Sentences: {len([s for s in sentences if s.strip()])}
📑 Paragraphs: {len([p for p in paragraphs if p.strip()])}"""

            if analysis_type == "basic":
                return basic_stats
            elif analysis_type == "detailed":
                avg_word_length = sum(len(word) for word in words) / len(words) if words else 0
                avg_sentence_length = len(words) / len([s for s in sentences if s.strip()]) if sentences else 0

                return basic_stats + f"""
📊 Average word length: {avg_word_length:.1f} characters
📊 Average sentence length: {avg_sentence_length:.1f} words
📊 Unique words: {len(set(word.lower() for word in words))}"""
            elif analysis_type == "readability":
                # Simple readability estimate
                avg_sentence_length = len(words) / len([s for s in sentences if s.strip()]) if sentences else 0
                avg_word_length = sum(len(word) for word in words) / len(words) if words else 0

                if avg_sentence_length < 15 and avg_word_length < 5:
                    level = "Easy"
                elif avg_sentence_length < 20 and avg_word_length < 6:
                    level = "Moderate"
                else:
                    level = "Complex"

                return basic_stats + f"""
📖 Readability: {level}
📊 Avg sentence length: {avg_sentence_length:.1f} words
📊 Avg word length: {avg_word_length:.1f} characters"""
            else:
                return "Analysis types: basic, detailed, readability"
        except Exception as e:
            return f"Text analysis error: {str(e)}"

    def json_formatter(
        self,
        json_text: str = Field(..., description="JSON text to format or validate"),
        operation: str = Field("format", description="Operation: format, validate, minify")
    ) -> str:
        """
        Format, validate, or minify JSON text.
        """
        try:
            # Parse JSON to validate
            data = json.loads(json_text)

            if operation == "format":
                formatted = json.dumps(data, indent=2, ensure_ascii=False)
                return f"Formatted JSON:\n```json\n{formatted}\n```"
            elif operation == "validate":
                return "✅ Valid JSON structure"
            elif operation == "minify":
                minified = json.dumps(data, separators=(',', ':'), ensure_ascii=False)
                return f"Minified JSON:\n{minified}"
            else:
                return "Operations: format, validate, minify"
        except json.JSONDecodeError as e:
            return f"❌ Invalid JSON: {str(e)}"
        except Exception as e:
            return f"JSON processing error: {str(e)}"

